const now = new Date();
const month = now.getMonth() + 1;
const day = now.getDate();
const weekOfMonth = Math.ceil(day / 7);
let season = '', seasonDesc = '';
if (month >= 3 && month <= 5) { season = '봄'; seasonDesc = '졸업/입학 시즌, 벚꽃 행사, 신학기'; }
else if (month >= 6 && month <= 8) { season = '여름'; seasonDesc = '워터파크, 야외 행사, 여름 축제, 체육대회'; }
else if (month >= 9 && month <= 11) { season = '가을'; seasonDesc = '운동회, 추석 명절, 기업 행사, 송년회 준비'; }
else { season = '겨울'; seasonDesc = '연말 송년회, 크리스마스, 신년 선물, 설 명절'; }
const specialEvents = [];
if (month === 2 || month === 3) specialEvents.push('졸업/입학 시즌');
if (month === 5) specialEvents.push('어린이날, 스승의날, 가정의달');
if (month === 9 || month === 10) specialEvents.push('추석 명절, 체육대회');
if (month === 12 || month === 1) specialEvents.push('연말연시, 신년');
const dateStr = now.toISOString().slice(0,10);
const endDate = dateStr;
const startDate = new Date(now.getTime() - 7*24*60*60*1000).toISOString().slice(0,10);
const blogTitle = `'26년 ${month}월 ${weekOfMonth}주 AI가 추천하는 판촉/홍보/답례품`;
return [{ json: { month, day, weekOfMonth, season, seasonDesc, specialEvents: specialEvents.join(', ') || '일반 시즌', dateStr, startDate, endDate, blogTitle } }];

const season = $('현재 시기 정보').first().json;
const trendRaw = $input.first().json;
let trendSummary = '트렌드 데이터 없음';
try {
  if (trendRaw.results) {
    trendSummary = trendRaw.results.map(r => {
      const max = Math.max(...r.data.map(d => d.ratio));
      return `${r.title}: 최고 검색비율 ${max.toFixed(1)}`;
    }).join('\n');
  }
} catch(e) {}
return [{ json: { ...season, trendSummary } }];

const d = $input.first().json;
const prev = $('1차 프롬프트 조립').first().json;
let raw = '';
if (d.candidates && d.candidates[0]) raw = d.candidates[0]['content']['parts'][0]['text'] || '';
raw = raw.replace(/```json\s*/g,'').replace(/```\s*/g,'').trim();
let title = prev.blogTitle, body = raw, hashtags = '';
try {
  const p = JSON.parse(raw);
  title = p.title || prev.blogTitle;
  body = p.body || raw;
  hashtags = p.hashtags || '';
} catch(e) {}
return [{ json: { ...prev, title, body_draft: body, hashtags_draft: hashtags } }];

const d = $input.first().json;
const prev = $('2차 프롬프트 조립').first().json;
let raw = '';
if (d.candidates && d.candidates[0]) raw = d.candidates[0]['content']['parts'][0]['text'] || '';
raw = raw.replace(/```json\s*/g,'').replace(/```\s*/g,'').trim();
let title = prev.title, body = raw, hashtags = prev.hashtags_draft;
try {
  const p = JSON.parse(raw);
  title = p.title || prev.title;
  body = p.body || raw;
  hashtags = p.hashtags || prev.hashtags_draft;
} catch(e) {}
const MAX = 1900;
const bodyChunks = [];
for (let i = 0; i < body.length; i += MAX) bodyChunks.push(body.slice(i, i + MAX));
return [{ json: { ...prev, title_final: title, body_final: body, bodyChunks_final: bodyChunks, hashtags_final: hashtags } }];

